"use strict";
(() => {
  // game-src/input.ts
  var KEY = {
    LEFT: 37,
    UP: 38,
    RIGHT: 39,
    DOWN: 40,
    W: 87,
    A: 65,
    S: 83,
    D: 68,
    SPACE: 32
  };
  var PREV_BITS_VAR = "__inputPrevBits";
  function readInput(scene2) {
    const im = scene2.getGame().getInputManager();
    let x = 0;
    let y = 0;
    if (im.isKeyPressed(KEY.LEFT) || im.isKeyPressed(KEY.A)) x -= 1;
    if (im.isKeyPressed(KEY.RIGHT) || im.isKeyPressed(KEY.D)) x += 1;
    if (im.isKeyPressed(KEY.UP) || im.isKeyPressed(KEY.W)) y -= 1;
    if (im.isKeyPressed(KEY.DOWN) || im.isKeyPressed(KEY.S)) y += 1;
    const space = im.isKeyPressed(KEY.SPACE);
    const mouse = im.isMouseButtonPressed(0);
    const fire3 = space || mouse;
    const prevVar = scene2.getVariables().get(PREV_BITS_VAR);
    const prev = prevVar.getAsNumber();
    const wasFire = (prev & (1 /* Fire */ | 2 /* Mouse */)) !== 0;
    const firePressed = fire3 && !wasFire;
    let next = 0;
    if (space) next |= 1 /* Fire */;
    if (mouse) next |= 2 /* Mouse */;
    prevVar.setNumber(next);
    return {
      axes: { x, y },
      fire: fire3,
      firePressed,
      cursor: { x: im.getCursorX(), y: im.getCursorY() }
    };
  }

  // game-src/gestures.ts
  var TAP_DURATION_MAX_SEC = 0.2;
  var TAP_MOVEMENT_MAX_PX = 12;
  var DOUBLE_TAP_WINDOW_SEC = 0.3;
  var V_PREV_PRESSED = "__gPrevPressed";
  var V_PRESS_TIME = "__gPressTime";
  var V_PRESS_X = "__gPressX";
  var V_PRESS_Y = "__gPressY";
  var V_DRAGGING = "__gDragging";
  var V_PENDING_TAP_T = "__gPendingTapTime";
  var V_SCENE_TIME = "__gSceneTime";
  function detectGesture(scene2, dt2, cursorX, cursorY, pressed) {
    const vars = scene2.getVariables();
    const now = vars.get(V_SCENE_TIME).getAsNumber() + dt2;
    vars.get(V_SCENE_TIME).setNumber(now);
    const wasPressed = vars.get(V_PREV_PRESSED).getAsNumber() === 1;
    vars.get(V_PREV_PRESSED).setNumber(pressed ? 1 : 0);
    let tap = false;
    let doubleTap = false;
    let dragging = vars.get(V_DRAGGING).getAsNumber() === 1;
    let dragStarted = false;
    if (pressed && !wasPressed) {
      vars.get(V_PRESS_TIME).setNumber(now);
      vars.get(V_PRESS_X).setNumber(cursorX);
      vars.get(V_PRESS_Y).setNumber(cursorY);
      vars.get(V_DRAGGING).setNumber(0);
      dragging = false;
    }
    if (pressed && wasPressed && !dragging) {
      const held = now - vars.get(V_PRESS_TIME).getAsNumber();
      const dx = cursorX - vars.get(V_PRESS_X).getAsNumber();
      const dy = cursorY - vars.get(V_PRESS_Y).getAsNumber();
      const moved = Math.hypot(dx, dy);
      if (held >= TAP_DURATION_MAX_SEC || moved >= TAP_MOVEMENT_MAX_PX) {
        dragging = true;
        dragStarted = true;
        vars.get(V_DRAGGING).setNumber(1);
      }
    }
    if (!pressed && wasPressed) {
      if (!dragging) {
        const pending2 = vars.get(V_PENDING_TAP_T).getAsNumber();
        if (pending2 > 0 && now - pending2 <= DOUBLE_TAP_WINDOW_SEC) {
          doubleTap = true;
          vars.get(V_PENDING_TAP_T).setNumber(0);
        } else {
          vars.get(V_PENDING_TAP_T).setNumber(now);
        }
      }
      vars.get(V_DRAGGING).setNumber(0);
      dragging = false;
    }
    const pending = vars.get(V_PENDING_TAP_T).getAsNumber();
    if (pending > 0 && now - pending > DOUBLE_TAP_WINDOW_SEC) {
      tap = true;
      vars.get(V_PENDING_TAP_T).setNumber(0);
    }
    return { tap, doubleTap, dragging, dragStarted };
  }

  // game-src/entities.ts
  var ObjectName = {
    Player: "Player",
    Enemy: "Enemy",
    Bullet: "Bullet",
    Cannon: "Cannon",
    EnemyBall: "EnemyBall",
    Castle: "Castle",
    Sea: "Sea",
    Target: "Target",
    DeadZone: "DeadZone",
    Island: "Island",
    Railing: "Railing",
    Crosshair: "Crosshair",
    HealthBar: "HealthBar",
    HealthBarBg: "HealthBarBg",
    CannonballUI: "CannonballUI",
    AmmoDot: "AmmoDot",
    ReloadPip: "ReloadPip",
    AmmoText: "AmmoText",
    LoseOverlay: "LoseOverlay",
    RestartButtonBg: "RestartButtonBg",
    GameOverText: "GameOverText",
    RestartButtonText: "RestartButtonText",
    PlayerHpFrame: "PlayerHpFrame",
    PlayerHpSection: "PlayerHpSection",
    ChargedBullet: "ChargedBullet",
    VictoryText: "VictoryText",
    ContinueButtonText: "ContinueButtonText"
  };
  function spawn(scene2, name, x, y) {
    const obj = scene2.createObject(name, x, y);
    if (!obj) {
      console.warn(`[entities] createObject('${name}') returned null \u2014 is it defined in the scene?`);
    }
    return obj;
  }
  function all(scene2, name) {
    return scene2.getObjects(name);
  }
  function firstOrNull(scene2, name) {
    const arr = scene2.getObjects(name);
    return arr.length > 0 ? arr[0] : null;
  }

  // game-src/projectiles.ts
  var FLIGHT_TIME_SEC = 2.25;
  var BALL_DISPLAY_SIZE_PX = 28;
  var CHARGED_BALL_DISPLAY_SIZE_PX = 44;
  var VIEWPORT_PEAK_MARGIN_PX = 24;
  var MIN_ARC_HEIGHT_PX = 80;
  function maxAllowedArcH(sy, ty, margin) {
    const u = ty - sy;
    const M = sy - margin;
    if (M <= 0) return Number.POSITIVE_INFINITY;
    const disc = 256 * M * (M + u);
    if (disc <= 0) return Number.POSITIVE_INFINITY;
    return (8 * u + 16 * M + Math.sqrt(disc)) / 32;
  }
  function centerOn(p, x, y) {
    p.setX(x - p.getWidth() / 2);
    p.setY(y - p.getHeight() / 2);
  }
  function fire(scene2, kind, startX, startY, targetX, targetY, opts = {}) {
    const p = spawn(scene2, kind, startX, startY);
    if (!p) return null;
    const charged = opts.charged === true;
    let nativeW = 0;
    if (kind === ObjectName.Bullet || kind === ObjectName.ChargedBullet || kind === ObjectName.EnemyBall) {
      nativeW = p.getWidth();
      const displaySize = charged ? CHARGED_BALL_DISPLAY_SIZE_PX : BALL_DISPLAY_SIZE_PX;
      if (nativeW > 0) p.setScale(displaySize / nativeW);
    }
    centerOn(p, startX, startY);
    if (charged) p.getVariables().get("charged").setNumber(1);
    const horizDist = Math.abs(targetX - startX);
    const vertSpan = Math.abs(targetY - startY);
    const desired = Math.max(MIN_ARC_HEIGHT_PX, vertSpan * 0.55 + horizDist * 0.45);
    const maxAllowed = maxAllowedArcH(startY, targetY, VIEWPORT_PEAK_MARGIN_PX);
    const arcH = Math.min(desired, maxAllowed);
    const v = p.getVariables();
    v.get("startX").setNumber(startX);
    v.get("startY").setNumber(startY);
    v.get("targetX").setNumber(targetX);
    v.get("targetY").setNumber(targetY);
    v.get("arcH").setNumber(arcH);
    v.get("xArcAmp").setNumber(opts.xArcAmp ?? 0);
    v.get("elapsed").setNumber(0);
    if (kind === ObjectName.Bullet || kind === ObjectName.ChargedBullet || kind === ObjectName.EnemyBall) {
      const baseSize = charged ? CHARGED_BALL_DISPLAY_SIZE_PX : BALL_DISPLAY_SIZE_PX;
      v.get("baseSize").setNumber(baseSize);
      v.get("nativeW").setNumber(nativeW);
    }
    return p;
  }
  function depthScale(t, kind) {
    if (kind === ObjectName.Bullet || kind === ObjectName.ChargedBullet) return 1 - 0.55 * t;
    if (kind === ObjectName.EnemyBall) return 0.45 + 0.55 * t;
    return 1;
  }
  function update(scene2, kind, dt2) {
    for (const p of all(scene2, kind)) {
      const v = p.getVariables();
      const elapsed = v.get("elapsed").getAsNumber() + dt2;
      if (elapsed >= FLIGHT_TIME_SEC) {
        p.deleteFromScene(scene2);
        continue;
      }
      v.get("elapsed").setNumber(elapsed);
      const t = elapsed / FLIGHT_TIME_SEC;
      const sx = v.get("startX").getAsNumber();
      const sy = v.get("startY").getAsNumber();
      const tx = v.get("targetX").getAsNumber();
      const ty = v.get("targetY").getAsNumber();
      const arcH = v.get("arcH").getAsNumber();
      const xArcAmp = v.get("xArcAmp").getAsNumber();
      const x = sx + (tx - sx) * t + xArcAmp * 4 * t * (1 - t);
      const y = sy + (ty - sy) * t - arcH * 4 * t * (1 - t);
      if (kind === ObjectName.Bullet || kind === ObjectName.ChargedBullet || kind === ObjectName.EnemyBall) {
        const baseSize = v.get("baseSize").getAsNumber();
        const nativeW = v.get("nativeW").getAsNumber();
        if (baseSize > 0 && nativeW > 0) {
          const size = baseSize * depthScale(t, kind);
          p.setScale(size / nativeW);
        }
      }
      centerOn(p, x, y);
    }
  }

  // game-src/hud.ts
  var MAX_AMMO = 4;
  var RELOAD_SEC = 4;
  var SHOT_COOLDOWN_SEC = 0.75;
  var UI_RIGHT_MARGIN = 12;
  var UI_TOP_MARGIN = 12;
  var TEXT_OFFSET_X = 86;
  var TEXT_OFFSET_Y = 20;
  var RELOAD_PIP_COUNT = 12;
  var RELOAD_PIP_RADIUS = 110;
  var HUD_INIT_VAR = "__hudInit";
  var HUD_AMMO_VAR = "__hudAmmo";
  var HUD_RELOAD_VAR = "__hudReload";
  var HUD_COOLDOWN_VAR = "__hudShotCooldown";
  var PIPS_SPAWNED_VAR = "__hudPipsSpawned";
  var UI_Z = 30;
  var TEXT_Z = 32;
  var PIP_Z = 40;
  function ensureHud(scene2) {
    const vars = scene2.getVariables();
    if (vars.get(HUD_INIT_VAR).getAsNumber() !== 0) return;
    vars.get(HUD_INIT_VAR).setNumber(1);
    vars.get(HUD_AMMO_VAR).setNumber(MAX_AMMO);
    vars.get(HUD_RELOAD_VAR).setNumber(0);
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const ui = spawn(scene2, ObjectName.CannonballUI, 0, 0);
    if (!ui) return;
    const uw = ui.getWidth();
    const ux = w - uw - UI_RIGHT_MARGIN;
    const uy = UI_TOP_MARGIN;
    ui.setX(ux);
    ui.setY(uy);
    ui.setZOrder(UI_Z);
    const text = spawn(scene2, ObjectName.AmmoText, 0, 0);
    if (text) {
      text.setX(ux + TEXT_OFFSET_X);
      text.setY(uy + TEXT_OFFSET_Y);
      text.setZOrder(TEXT_Z);
      text.setString(String(MAX_AMMO));
    }
    console.log(`[hud] ammo UI at (${ux}, ${uy})`);
  }
  function canFire(scene2, cost) {
    const vars = scene2.getVariables();
    if (vars.get(HUD_RELOAD_VAR).getAsNumber() > 0) return false;
    if (vars.get(HUD_COOLDOWN_VAR).getAsNumber() > 0) return false;
    return vars.get(HUD_AMMO_VAR).getAsNumber() >= cost;
  }
  function consumeAmmo(scene2, cost) {
    const vars = scene2.getVariables();
    const before = vars.get(HUD_AMMO_VAR).getAsNumber();
    const after = Math.max(0, before - cost);
    vars.get(HUD_AMMO_VAR).setNumber(after);
    if (after <= 0) {
      vars.get(HUD_RELOAD_VAR).setNumber(RELOAD_SEC);
      console.log(`[hud] empty \u2014 reloading for ${RELOAD_SEC}s`);
    }
    vars.get(HUD_COOLDOWN_VAR).setNumber(SHOT_COOLDOWN_SEC);
    return after;
  }
  function spawnReloadPipsIfNeeded(scene2, cannon2) {
    if (!cannon2) return;
    const vars = scene2.getVariables();
    if (vars.get(PIPS_SPAWNED_VAR).getAsNumber() === 1) return;
    vars.get(PIPS_SPAWNED_VAR).setNumber(1);
    const cx = cannon2.getX() + cannon2.getCenterX();
    const cy = cannon2.getY() + cannon2.getCenterY();
    for (let i = 0; i < RELOAD_PIP_COUNT; i++) {
      const angle = i / RELOAD_PIP_COUNT * 2 * Math.PI - Math.PI / 2;
      const x = cx + RELOAD_PIP_RADIUS * Math.cos(angle);
      const y = cy + RELOAD_PIP_RADIUS * Math.sin(angle);
      const pip = spawn(scene2, ObjectName.ReloadPip, 0, 0);
      if (!pip) continue;
      pip.setX(x - pip.getWidth() / 2);
      pip.setY(y - pip.getHeight() / 2);
      pip.setZOrder(PIP_Z);
      pip.hide(true);
      pip.getVariables().get("idx").setNumber(i);
    }
  }
  function tick(scene2, dt2, cannon2) {
    const vars = scene2.getVariables();
    const reloadLeft = vars.get(HUD_RELOAD_VAR).getAsNumber();
    if (reloadLeft > 0) {
      const next = reloadLeft - dt2;
      if (next <= 0) {
        vars.get(HUD_RELOAD_VAR).setNumber(0);
        vars.get(HUD_AMMO_VAR).setNumber(MAX_AMMO);
        console.log(`[hud] reload complete`);
      } else {
        vars.get(HUD_RELOAD_VAR).setNumber(next);
      }
    }
    const cd = vars.get(HUD_COOLDOWN_VAR).getAsNumber();
    if (cd > 0) vars.get(HUD_COOLDOWN_VAR).setNumber(Math.max(0, cd - dt2));
    const ammo = vars.get(HUD_AMMO_VAR).getAsNumber();
    const reloading = vars.get(HUD_RELOAD_VAR).getAsNumber() > 0;
    const text = firstOrNull(scene2, ObjectName.AmmoText);
    if (text) text.setString(reloading ? ":" : String(ammo));
    spawnReloadPipsIfNeeded(scene2, cannon2);
    if (reloading) {
      const duration = RELOAD_SEC;
      const left = vars.get(HUD_RELOAD_VAR).getAsNumber();
      const progress = Math.max(0, Math.min(1, 1 - left / duration));
      const visibleCount = Math.ceil(progress * RELOAD_PIP_COUNT);
      for (const pip of all(scene2, ObjectName.ReloadPip)) {
        const idx = pip.getVariables().get("idx").getAsNumber();
        pip.hide(idx >= visibleCount);
      }
    } else {
      for (const pip of all(scene2, ObjectName.ReloadPip)) pip.hide(true);
    }
  }

  // game-src/cannon.ts
  var AIM_CENTER_DEG = -90;
  var AIM_SPREAD_DEG = 15;
  var TARGET_BAND_Y = 270;
  var AIM_DEG_PER_PX = 1 / 8;
  var AIM_DEG_VAR = "__aimDeg";
  var PREV_CURSOR_X_VAR = "__prevCursorX";
  var AIM_INIT_VAR = "__aimInit";
  var BOTTOM_MARGIN = 14;
  var RAILING_BOTTOM_MARGIN = 0;
  var CANNON_Z = 10;
  var RAILING_Z = 5;
  var CROSSHAIR_Z = 15;
  function ensureCannon(scene2) {
    let c = firstOrNull(scene2, ObjectName.Cannon);
    if (c) return c;
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const h = game.getGameResolutionHeight();
    c = spawn(scene2, ObjectName.Cannon, 0, 0);
    if (c) {
      const cw = c.getWidth();
      const ch = c.getHeight();
      c.setX(w / 2 - cw / 2);
      c.setY(h - ch - BOTTOM_MARGIN);
      c.setZOrder(CANNON_Z);
      console.log(`[cannon] spawned ${cw}\xD7${ch}`);
    }
    const r = spawn(scene2, ObjectName.Railing, 0, 0);
    if (r) {
      const rw = r.getWidth();
      const rh = r.getHeight();
      r.setX(w / 2 - rw / 2);
      r.setY(h - rh - RAILING_BOTTOM_MARGIN);
      r.setZOrder(RAILING_Z);
    }
    return c;
  }
  function cannonCenter(cannon2) {
    return {
      x: cannon2.getX() + cannon2.getCenterX(),
      y: cannon2.getY() + cannon2.getCenterY()
    };
  }
  function aimTarget(scene2, cannon2, aimDeg) {
    const rad = aimDeg * Math.PI / 180;
    const dx = Math.cos(rad);
    const dy = Math.sin(rad);
    const { x: cx, y: cy } = cannonCenter(cannon2);
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const h = game.getGameResolutionHeight();
    let tx, ty;
    if (dy < -0.05) {
      const tDist = (TARGET_BAND_Y - cy) / dy;
      tx = cx + dx * tDist;
      ty = TARGET_BAND_Y;
    } else {
      tx = cx + dx * 400;
      ty = cy + dy * 400;
    }
    tx = Math.max(20, Math.min(w - 20, tx));
    ty = Math.max(20, Math.min(h - 20, ty));
    return { x: tx, y: ty };
  }
  function aim(scene2, cannon2, cursorX, dragging) {
    const vars = scene2.getVariables();
    if (vars.get(AIM_INIT_VAR).getAsNumber() === 0) {
      vars.get(AIM_INIT_VAR).setNumber(1);
      vars.get(AIM_DEG_VAR).setNumber(AIM_CENTER_DEG);
      vars.get(PREV_CURSOR_X_VAR).setNumber(cursorX);
    }
    const prev = vars.get(PREV_CURSOR_X_VAR).getAsNumber();
    const dx = cursorX - prev;
    vars.get(PREV_CURSOR_X_VAR).setNumber(cursorX);
    let aimDeg = vars.get(AIM_DEG_VAR).getAsNumber();
    if (dragging) {
      aimDeg += dx * AIM_DEG_PER_PX;
      aimDeg = Math.max(AIM_CENTER_DEG - AIM_SPREAD_DEG, Math.min(AIM_CENTER_DEG + AIM_SPREAD_DEG, aimDeg));
      vars.get(AIM_DEG_VAR).setNumber(aimDeg);
    }
    cannon2.setAngle(aimDeg + 90);
    return aimDeg;
  }
  function updateCrosshair(scene2, cannon2, aimDeg) {
    let cross = firstOrNull(scene2, ObjectName.Crosshair);
    if (!cross) {
      cross = spawn(scene2, ObjectName.Crosshair, 0, 0);
      if (cross) cross.setZOrder(CROSSHAIR_Z);
    }
    if (!cross) return;
    const t = aimTarget(scene2, cannon2, aimDeg);
    cross.setX(t.x - cross.getWidth() / 2);
    cross.setY(t.y - cross.getHeight() / 2);
  }
  function fire2(scene2, cannon2, aimDeg, charged = false) {
    const cost = charged ? 2 : 1;
    if (!canFire(scene2, cost)) return false;
    const rad = aimDeg * Math.PI / 180;
    const dx = Math.cos(rad);
    const dy = Math.sin(rad);
    const { x: cx, y: cy } = cannonCenter(cannon2);
    const muzzleOffset = 80;
    const muzzleX = cx + dx * muzzleOffset;
    const muzzleY = cy + dy * muzzleOffset;
    const target = aimTarget(scene2, cannon2, aimDeg);
    const horizDelta = target.x - muzzleX;
    const dir = horizDelta === 0 ? 1 : Math.sign(horizDelta);
    const xArcAmp = horizDelta * 0.5 + dir * 40;
    const kind = charged ? ObjectName.ChargedBullet : ObjectName.Bullet;
    fire(scene2, kind, muzzleX, muzzleY, target.x, target.y, { charged, xArcAmp });
    consumeAmmo(scene2, cost);
    console.log(`[cannon] fire${charged ? " CHARGED" : ""} aim=${aimDeg.toFixed(1)}\xB0 muzzle=(${muzzleX.toFixed(0)},${muzzleY.toFixed(0)}) \u2192 (${target.x.toFixed(0)},${target.y.toFixed(0)})`);
    return true;
  }

  // game-src/background.ts
  var SEA_Z = -20;
  var ISLAND_Z = -15;
  var SKY_HEIGHT_PX = 130;
  var ISLAND_Y = 110;
  var DEADZONE_INSET_PX = 56;
  var INIT_VAR = "__bgInit";
  function deadZoneInset() {
    return DEADZONE_INSET_PX;
  }
  function ensureBackground(scene2) {
    const vars = scene2.getVariables();
    if (vars.get(INIT_VAR).getAsNumber() !== 0) return;
    vars.get(INIT_VAR).setNumber(1);
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const h = game.getGameResolutionHeight();
    const sea = spawn(scene2, ObjectName.Sea, 0, SKY_HEIGHT_PX);
    if (sea) {
      sea.setWidth(w);
      sea.setHeight(Math.max(h - SKY_HEIGHT_PX, 0) + 1200);
      sea.setZOrder(SEA_Z);
    }
    const island = spawn(scene2, ObjectName.Island, 0, 0);
    if (island) {
      const iw = island.getWidth();
      island.setX(w / 2 - iw / 2);
      island.setY(ISLAND_Y);
      island.setZOrder(ISLAND_Z);
    }
    console.log(`[background] viewport ${w}\xD7${h}, sky 0..${SKY_HEIGHT_PX}, sea ${SKY_HEIGHT_PX}..${h}`);
  }

  // game-src/enemy.ts
  var FIRE_INTERVAL_SEC = 3.9;
  var ENEMY_MAGAZINE = 3;
  var ENEMY_RELOAD_SEC = 3.25;
  var SPAWN_GAP_SEC = 1;
  var ENTRY_SPEED_PX_PER_SEC = 220;
  var INITIAL_HP = 2;
  var TOTAL_SHIPS_TO_SINK = 3;
  var FLASH_DURATION_SEC = 0.15;
  var FLASH_COLOR_DIRECT = "255;255;255";
  var FLASH_COLOR_OFFTARGET = "200;200;80";
  var FLASH_COLOR_NONE = "255;255;255";
  var FLASH_OPACITY_DIRECT = 160;
  var FLASH_OPACITY_DEFAULT = 255;
  var HEALTHBAR_OFFSET_Y = -16;
  var HEALTHBAR_NATIVE_W = 60;
  var STOP_INSIDE_PLAYFIELD_PX = 6;
  var TARGET_OFFSET_FRAC_X = 0.5;
  var TARGET_OFFSET_FRAC_Y = 0.7;
  var SUNK_COUNT_VAR = "__shipsSunk";
  var NEXT_SIDE_VAR = "__nextSide";
  var SPAWN_TIMER_VAR = "__spawnTimer";
  var INIT_FLAG_VAR = "__enemyInit";
  var SHIP_ID_COUNTER = "__shipIdCounter";
  function nextShipId(scene2) {
    const counter = scene2.getVariables().get(SHIP_ID_COUNTER);
    const id = counter.getAsNumber() + 1;
    counter.setNumber(id);
    return id;
  }
  function findTargetForShip(scene2, shipId) {
    for (const t of all(scene2, ObjectName.Target)) {
      if (t.getVariables().get("shipId").getAsNumber() === shipId) return t;
    }
    return null;
  }
  function findShipForTarget(scene2, target) {
    const id = target.getVariables().get("shipId").getAsNumber();
    for (const e of all(scene2, ObjectName.Enemy)) {
      if (e.getVariables().get("shipId").getAsNumber() === id) return e;
    }
    return null;
  }
  var ENEMY_Y = 140;
  function spawnShip(scene2, side) {
    const w = scene2.getGame().getGameResolutionWidth();
    const dz = deadZoneInset();
    const y = ENEMY_Y;
    const e = spawn(scene2, ObjectName.Enemy, side === "left" ? -400 : w + 400, y);
    if (!e) return null;
    const ew = e.getWidth();
    const startX = side === "left" ? -ew - 8 : w + 8;
    const playfieldLeft = dz + STOP_INSIDE_PLAYFIELD_PX;
