  var CHARGED_MULTIPLIER = 2.5;
  var CHARGED_INTERCEPTED_MULTIPLIER = 1.25;
  var ENEMY_BALL_DAMAGE = 1;
  function bulletDamage(charged, intercepted, body) {
    const base = body ? BULLET_BODY_DAMAGE : BULLET_DAMAGE;
    if (!charged) return base;
    return base * (intercepted ? CHARGED_INTERCEPTED_MULTIPLIER : CHARGED_MULTIPLIER);
  }
  function hit(a, b) {
