    }
    const buttonBg = spawn(scene2, ObjectName.RestartButtonBg, 0, 0);
    if (buttonBg) {
      buttonBg.setWidth(BUTTON_W2);
      buttonBg.setHeight(BUTTON_H2);
      buttonBg.setX(w / 2 - BUTTON_W2 / 2);
      buttonBg.setY(h * BUTTON_Y_FRACTION2);
      buttonBg.setZOrder(Z_BUTTON_BG2);
      buttonBg.getVariables().get("isContinueButton").setNumber(1);
    }
    const buttonText = spawn(scene2, ObjectName.ContinueButtonText, 0, 0);
    if (buttonText) {
      const tw = buttonText.getWidth() || 160;
      const th = buttonText.getHeight() || 36;
      buttonText.setX(w / 2 - tw / 2);
      buttonText.setY(h * BUTTON_Y_FRACTION2 + BUTTON_H2 / 2 - th / 2);
      buttonText.setZOrder(Z_TEXT2);
    }
    console.log(`[win] spawned`);
  }
  function continueButton(scene2) {
    for (const bg of scene2.getObjects(ObjectName.RestartButtonBg)) {
      if (bg.getVariables().get("isContinueButton").getAsNumber() === 1) return bg;
    }
    return firstOrNull(scene2, ObjectName.RestartButtonBg);
  }
  function tick6(scene2, cursorX, cursorY, firePressed) {
    ensureSpawned2(scene2);
    if (!firePressed) return;
    const bg = continueButton(scene2);
    if (!bg) return;
    const x = bg.getX(), y = bg.getY(), w = bg.getWidth(), h = bg.getHeight();
    if (cursorX >= x && cursorX < x + w && cursorY >= y && cursorY < y + h) {
      console.log(`[win] continue \u2192 ${NEXT_SCENE_NAME}`);
      scene2.requestChange(REPLACE_SCENE2, NEXT_SCENE_NAME);
    }
  }

  // game-src/main.ts
  var scene = runtimeScene;
  ensureInit(scene);
  ensureBackground(scene);
  var cannon = ensureCannon(scene);
  ensureHud(scene);
  var playing = getState(scene) === "playing";
  var dt = scene.getElapsedTime() / 1e3;
  var input = readInput(scene);
  var gesture = detectGesture(scene, dt, input.cursor.x, input.cursor.y, input.fire);
  if (cannon && playing) {
    const aimDeg = aim(scene, cannon, input.cursor.x, gesture.dragging);
    updateCrosshair(scene, cannon, aimDeg);
    if (gesture.tap) fire2(
      scene,
      cannon,
      aimDeg,
      /*charged*/
      false
    );
    if (gesture.doubleTap) fire2(
      scene,
      cannon,
      aimDeg,
      /*charged*/
      true
    );
    tick2(
      scene,
      dt,
      cannon.getX() + cannon.getCenterX(),
      cannon.getY() + cannon.getCenterY()
    );
  }
  update(scene, ObjectName.Bullet, dt);
  update(scene, ObjectName.ChargedBullet, dt);
  update(scene, ObjectName.EnemyBall, dt);
  tick(scene, dt, cannon);
  tick4(scene, dt);
  tick3(scene, dt);
  if (playing) {
    resolveBulletHits(scene);
    resolveEnemyBallHits(scene, cannon);
    if (isLevelComplete(scene)) markWon(scene);
  }
  var endState = getState(scene);
  if (endState === "lost") {
    tick5(scene, input.cursor.x, input.cursor.y, input.firePressed);
  } else if (endState === "won") {
    tick6(scene, input.cursor.x, input.cursor.y, input.firePressed);
  }
})();
